# Tool display mode
_show_tools = True
_tool_call_count = 0         # counter for current response
_tool_output_buffer = []     # buffered output lines when hidden
_tool_counter_active = False # whether we have a counter line on screen
_tool_output_shown = False   # whether buffered output is currently displayed


def _reset_tool_tracking() -> None:
    """Reset tool tracking for a new response."""
    global _tool_call_count, _tool_output_buffer, _tool_counter_active, _tool_output_shown
    _tool_call_count = 0
    _tool_output_buffer = []
    _tool_counter_active = False
    _tool_output_shown = False


def _update_tool_counter() -> None:
    """In hidden mode, update the single-line tool counter in-place."""
    global _tool_counter_active
    msg = f"  {DIM}Tools called: {RESET}{BOLD}{_tool_call_count}{RESET}{DIM}  (press o to show/hide){RESET}"
    if _tool_counter_active:
        # Move up to overwrite the previous counter line
        sys.stdout.write(f"\033[A\r\033[K{msg}\n")
    else:
        sys.stdout.write(f"{msg}\n")
        _tool_counter_active = True
    sys.stdout.flush()


def _toggle_tool_output() -> None:
    """Toggle display of buffered tool output (called from EscapeWatcher on 'o')."""
    global _tool_output_shown
    if not _tool_output_buffer:
        return
    if not _tool_output_shown:
        # Show buffered output below the counter
        for line in _tool_output_buffer:
            sys.stdout.write(f"{line}\n")
        sys.stdout.flush()
        _tool_output_shown = True
    else:
        # Hide: move cursor up past the output and clear lines
        line_count = len(_tool_output_buffer)
        for _ in range(line_count):
            sys.stdout.write(f"\033[A\r\033[K")
        sys.stdout.flush()
        _tool_output_shown = False


def _format_tool_call(name: str, args: dict) -> list[str]:
    """Format a tool call box as a list of lines."""
    icon = TOOL_ICONS.get(name, "⚡")
    verb = TOOL_VERBS.get(name, "Running")
    max_w = max(20, _term_cols() - 8)

    lines = []
    lines.append(f"\n{_box_top(f'{FG_ORANGE}{BOLD}{icon} {verb}{RESET}')}")

    if name == "exa_search":
        lines.append(_box_mid(f"{CYAN}{name}{RESET}({MAGENTA}query{RESET}={WHITE}\"{args.get('query', '')}\"{RESET})"))
    elif name == "execute_command":
        cmd = args.get("command", "")
        if len(cmd) > max_w:
            cmd = cmd[:max_w - 3] + "..."
        lines.append(_box_mid(f"{YELLOW}$ {cmd}{RESET}"))
    elif name in ("read_file", "write_file", "edit_file"):
        lines.append(_box_mid(f"{CYAN}{name}{RESET} {WHITE}{args.get('path', '')}{RESET}"))
    elif name == "list_directory":
        p = args.get("path", ".")
        pat = args.get("pattern", "")
        label = f"{p}/{pat}" if pat else p
        lines.append(_box_mid(f"{CYAN}{name}{RESET} {WHITE}{label}{RESET}"))
    elif name == "search_files":
        lines.append(_box_mid(f"{CYAN}{name}{RESET} {MAGENTA}/{args.get('pattern', '')}/{RESET} in {WHITE}{args.get('path', '.')}{RESET}"))
    elif name == "web_fetch":
        lines.append(_box_mid(f"{CYAN}{args.get('method', 'GET')}{RESET} {WHITE}{args.get('url', '')}{RESET}"))
    elif name == "memory_store":
        lines.append(_box_mid(f"{MAGENTA}{args.get('name', '')}{RESET} {DIM}[{args.get('type', 'general')}]{RESET}"))
    elif name == "memory_recall":
        q = args.get("query", "(list all)")
        lines.append(_box_mid(f"{MAGENTA}{q}{RESET}"))
    elif name == "memory_shared":
        action = args.get("action", "recall")
        scope = args.get("scope", "global")
        scope_label = "team" if scope == "team" else "main"
        if action == "store":
            lines.append(_box_mid(f"{CYAN}store → {scope_label}:{RESET} {MAGENTA}{args.get('name', '')}{RESET}"))
        else:
            q = args.get("query", "(list all)")
            lines.append(_box_mid(f"{CYAN}recall ← {scope_label}:{RESET} {MAGENTA}{q}{RESET}"))
    elif name == "memory_delete":
        lines.append(_box_mid(f"{RED}{args.get('name', '')}{RESET}"))
    elif name == "delegate_task":
        lines.append(_box_mid(f"{CYAN}agent:{RESET} {BOLD}{args.get('agent', '')}{RESET}"))
        task_preview = args.get("task", "")[:max_w]
        lines.append(_box_mid(f"{DIM}{task_preview}{RESET}"))
    elif name == "use_skill":
        lines.append(_box_mid(f"{MAGENTA}{args.get('skill', '')}{RESET}"))
    else:
        summary = ", ".join(f"{k}={v!r}" for k, v in list(args.items())[:3])
        if len(summary) > max_w:
            summary = summary[:max_w - 3] + "..."
        lines.append(_box_mid(f"{CYAN}{name}{RESET}({summary})"))

    lines.append(_box_bot())
    return lines


def _display_tool_call(name: str, args: dict) -> None:
    """Print a styled tool invocation box, or buffer it in hidden mode."""
    global _tool_call_count
    _tool_call_count += 1
    formatted = _format_tool_call(name, args)

    if _show_tools:
        for line in formatted:
            print(line)
        sys.stdout.flush()
    else:
        _tool_output_buffer.extend(formatted)
        _update_tool_counter()


def _format_tool_result(name: str, result_str: str) -> list[str]:
    """Format a tool result summary box as a list of lines."""
    max_w = max(20, _term_cols() - 8)
    try:
        rdata = json.loads(result_str)
    except json.JSONDecodeError:
        return []

    out = []

    if rdata.get("error"):
        out.append(_box_top(f"{RED}{BOLD}✘ Error{RESET}"))
        for line in rdata["error"].split("\n")[:5]:
            out.append(_box_mid(line[:max_w]))
        out.append(f"{_box_bot()}\n")
        return out

    if name == "exa_search":
        count = rdata.get("result_count", 0)
        out.append(_box_top(f"{GREEN}{BOLD}✔ {count} results{RESET}"))
        for r in rdata.get("results", [])[:3]:
            out.append(_box_mid(f"{BOLD}{r.get('title', '')[:max_w]}{RESET}"))
        if count > 3:
            out.append(_box_mid(f"{DIM}... and {count - 3} more{RESET}"))
    elif name == "read_file":
        total = rdata.get("total_lines", 0)
        showing = rdata.get("showing", "")
        out.append(_box_top(f"{GREEN}{BOLD}✔ {total} lines{RESET} {DIM}(showing {showing}){RESET}"))
        content = rdata.get("content", "")
        lines = content.split("\n")
        for line in lines[:5]:
            out.append(_box_mid(f"{DIM}{line[:max_w]}{RESET}"))
        if len(lines) > 5:
            out.append(_box_mid(f"{DIM}... {len(lines) - 5} more lines{RESET}"))
    elif name == "write_file":
        out.append(_box_top(f"{GREEN}{BOLD}✔ Written{RESET}"))
        out.append(_box_mid(f"{rdata.get('path', '')} ({rdata.get('size', 0)} bytes)"))
    elif name == "edit_file":
        n = rdata.get("replacements", 0)
        out.append(_box_top(f"{GREEN}{BOLD}✔ {n} replacement{'s' if n != 1 else ''}{RESET}"))
        out.append(_box_mid(f"{rdata.get('path', '')}"))
    elif name == "list_directory":
        count = rdata.get("count", 0)
        out.append(_box_top(f"{GREEN}{BOLD}✔ {count} entries{RESET}"))
        for e in rdata.get("entries", [])[:8]:
            icon = "d" if e.get("type") == "directory" else " "
            out.append(_box_mid(f"{icon} {e.get('name', '')}"))
        if count > 8:
            out.append(_box_mid(f"{DIM}... and {count - 8} more{RESET}"))
    elif name == "search_files":
        mc = rdata.get("match_count", 0)
        fs = rdata.get("files_searched", 0)
        out.append(_box_top(f"{GREEN}{BOLD}✔ {mc} matches{RESET} {DIM}({fs} files searched){RESET}"))
        for m in rdata.get("matches", [])[:5]:
            out.append(_box_mid(f"{CYAN}{m.get('file', '')}:{m.get('line', '')}{RESET} {m.get('text', '')[:max_w]}"))
        if mc > 5:
            out.append(_box_mid(f"{DIM}... and {mc - 5} more{RESET}"))
    elif name == "execute_command":
        ec = rdata.get("exit_code", -1)
        label = f"{GREEN}{BOLD}✔ exit {ec}{RESET}" if ec == 0 else f"{RED}{BOLD}✘ exit {ec}{RESET}"
        out.append(_box_top(label))
        output = rdata.get("output", "")
        lines = output.split("\n")
        for line in lines[:10]:
            out.append(_box_mid(f"{DIM}{line[:max_w]}{RESET}"))
        if len(lines) > 10:
            out.append(_box_mid(f"{DIM}... {len(lines) - 10} more lines{RESET}"))
    elif name == "web_fetch":
        status = rdata.get("status", "")
        length = rdata.get("length", 0)
        out.append(_box_top(f"{GREEN}{BOLD}✔ HTTP {status}{RESET} {DIM}({length} chars){RESET}"))
        content = rdata.get("content", "")
        lines = content.split("\n")
        for line in lines[:5]:
            out.append(_box_mid(f"{DIM}{line[:max_w]}{RESET}"))
        if len(lines) > 5:
            out.append(_box_mid(f"{DIM}... {len(lines) - 5} more lines{RESET}"))
    elif name == "memory_store":
        out.append(_box_top(f"{GREEN}{BOLD}✔ Stored{RESET}"))
        out.append(_box_mid(f"{rdata.get('name', '')} → {rdata.get('file', '')}"))
    elif name == "memory_recall":
        count = rdata.get("count", 0)
        out.append(_box_top(f"{GREEN}{BOLD}✔ {count} memories{RESET}"))
        for r in rdata.get("results", [])[:5]:
            out.append(_box_mid(f"{BOLD}{r.get('name', '')}{RESET} {DIM}[{r.get('type', '')}]{RESET}"))
            desc = r.get("description", "")
            if desc:
                out.append(_box_mid(f"  {DIM}{desc[:max_w]}{RESET}"))
        if count > 5:
            out.append(_box_mid(f"{DIM}... and {count - 5} more{RESET}"))
    elif name == "memory_shared":
        source = rdata.get("source", "main")
        if rdata.get("status") == "stored":
            out.append(_box_top(f"{GREEN}{BOLD}✔ Stored → {source}{RESET}"))
            out.append(_box_mid(f"{rdata.get('name', '')} → {rdata.get('file', '')}"))
        else:
            count = rdata.get("count", 0)
            out.append(_box_top(f"{GREEN}{BOLD}✔ {count} shared memories{RESET} {DIM}({source}){RESET}"))
            for r in rdata.get("results", [])[:5]:
                out.append(_box_mid(f"{BOLD}{r.get('name', '')}{RESET} {DIM}[{r.get('type', '')}]{RESET}"))
            if count > 5:
                out.append(_box_mid(f"{DIM}... and {count - 5} more{RESET}"))
    elif name == "memory_delete":
        out.append(_box_top(f"{GREEN}{BOLD}✔ Deleted{RESET}"))
        out.append(_box_mid(f"{rdata.get('name', '')}"))
    elif name == "delegate_task":
        agent = rdata.get("agent", "")
        resp = rdata.get("response", "")
        out.append(_box_top(f"{GREEN}{BOLD}✔ {agent} responded{RESET}"))
        for line in resp.split("\n")[:8]:
            out.append(_box_mid(f"{DIM}{line[:max_w]}{RESET}"))
        resp_lines = resp.split("\n")
        if len(resp_lines) > 8:
            out.append(_box_mid(f"{DIM}... {len(resp_lines) - 8} more lines{RESET}"))
    elif name == "use_skill":
        skill = rdata.get("skill", "")
        instructions = rdata.get("instructions", "")
        line_count = len(instructions.split("\n"))
        out.append(_box_top(f"{GREEN}{BOLD}✔ {skill}{RESET} {DIM}({line_count} lines loaded){RESET}"))
    else:
        out.append(_box_top(f"{GREEN}{BOLD}✔ Done{RESET}"))

    out.append(f"{_box_bot()}\n")
    return out


def _display_tool_result(name: str, result_str: str) -> None:
    """Print a styled tool result summary box, or buffer it in hidden mode."""
    formatted = _format_tool_result(name, result_str)
    if _show_tools:
        for line in formatted:
            print(line)
        sys.stdout.flush()
    else:
        _tool_output_buffer.extend(formatted)
        _update_tool_counter()


# --- Worker Subagent Tool Handlers (v8.0.0) ---

def tool_get_artifact_detail(args: dict) -> str:
    """Retrieve raw content from a worker artifact."""
    artifact_id = args.get("artifact_id", "")
    query = args.get("query", "")
    offset = args.get("offset", 0)
    limit = args.get("limit", 16384)
    if not artifact_id:
        return _err("artifact_id is required")

    agent = getattr(_thread_local, 'current_agent', None) or _current_agent
    agent_id = agent.agent_id if agent else "main"
    artifacts_root = os.path.join(AGENTS_DIR, agent_id, "artifacts")

    # Search for the artifact file
    artifact_path = None
    if os.path.exists(artifacts_root):
        for root, dirs, files in os.walk(artifacts_root):
            if artifact_id in files:
                artifact_path = os.path.join(root, artifact_id)
                break
    if not artifact_path or not os.path.exists(artifact_path):
        return _err(f"Artifact '{artifact_id}' not found")

    try:
        with open(artifact_path) as f:
            data = json.load(f)
    except (json.JSONDecodeError, OSError) as e:
        return _err(f"Failed to read artifact: {e}")

    raw = data.get("raw_result", "")

    if query:
        lines = raw.splitlines()
        matches = []
        for i, line in enumerate(lines):
            if query.lower() in line.lower():
                start = max(0, i - 2)
                end = min(len(lines), i + 3)
                for j in range(start, end):
                    if j not in [m[0] for m in matches]:
                        matches.append((j, lines[j]))
        if matches:
            raw = "\n".join(f"{m[0]+1}: {m[1]}" for m in matches)
        else:
            raw = f"(no matches for '{query}' in {len(lines)} lines)"

    if offset:
        raw = raw[offset:]
    if len(raw) > limit:
        raw = raw[:limit] + f"\n\n[... truncated at {limit} chars, {len(data.get('raw_result',''))} total]"

    return _ok({
        "artifact_id": artifact_id,
        "tool": data.get("tool", ""),
        "content": raw,
        "total_size": data.get("size_bytes", len(raw)),
    })


def tool_worker_status(args: dict) -> str:
    """Get current state of worker subagents."""
    from execution import get_worker_registry
    registry = get_worker_registry()
    worker_id = args.get("worker_id")
    if worker_id:
        w = registry.get(worker_id)
        if not w:
            return _err(f"Worker '{worker_id}' not found")
        return _ok({"workers": [registry.to_status_dict(w)]})
    session_id = getattr(_thread_local, 'current_session_id', None) or ""
    workers = registry.list_session(session_id)
    return _ok({"workers": [registry.to_status_dict(w) for w in workers]})


def tool_worker_abort(args: dict) -> str:
    """Abort a running worker."""
    from execution import get_worker_registry
    worker_id = args.get("worker_id", "")
    reason = args.get("reason", "user requested abort")
    if not worker_id:
        return _err("worker_id is required")
    ok = get_worker_registry().cancel(worker_id, reason)
    return _ok({"aborted": ok, "worker_id": worker_id})


def tool_worker_pause(args: dict) -> str:
    """Pause a running worker."""
    from execution import get_worker_registry
    worker_id = args.get("worker_id", "")
    reason = args.get("reason", "")
    if not worker_id:
        return _err("worker_id is required")
    ok = get_worker_registry().pause(worker_id, reason)
    if not ok:
        return _err(f"Cannot pause worker '{worker_id}' (not running or not found)")
    return _ok({"paused": True, "worker_id": worker_id})


def tool_worker_resume(args: dict) -> str:
    """Resume a paused worker."""
    from execution import get_worker_registry
    worker_id = args.get("worker_id", "")
    if not worker_id:
        return _err("worker_id is required")
    ok = get_worker_registry().resume(worker_id)
    if not ok:
        return _err(f"Cannot resume worker '{worker_id}' (not paused or not found)")
    return _ok({"resumed": True, "worker_id": worker_id})


def tool_worker_send(args: dict) -> str:
    """Send input to a running or paused worker."""
    from execution import get_worker_registry
    worker_id = args.get("worker_id", "")
    message = args.get("message", "")
    role = args.get("role", "user")
    if not worker_id or not message:
        return _err("worker_id and message are required")
    ok = get_worker_registry().send(worker_id, message, role)
    if not ok:
        return _err(f"Cannot send to worker '{worker_id}' (terminal state or not found)")
    return _ok({"sent": True, "worker_id": worker_id})


def tool_worker_ask_user(args: dict) -> str:
    """Ask the user a question from within a worker subagent.

    Accepts single-question (`question` str) or a 1-item `questions` array.
    Multi-question batches are not supported inside workers — call once per question.
    """
    from execution import get_worker_registry
    worker_id = getattr(_thread_local, 'current_worker_id', None)
    if not worker_id:
        return _err("worker_ask_user can only be called from within a worker subagent")
    questions, _ = _normalize_ask_questions(args)
    if not questions:
        return _err("question or questions is required")
    if len(questions) > 1:
        return _err("worker_ask_user does not support question batches yet — call once per question")
    q0 = questions[0]
    context_summary = args.get("context_summary", "")
    timeout = args.get("timeout_seconds", 300)
    answer = get_worker_registry().ask_user(
        worker_id, q0["question"], q0.get("options"), context_summary, timeout
    )
    if answer is None:
        return _err("No answer received (timed out or worker was aborted)")
    return _ok({"answer": answer})


# --- Native-loop ask_user: session-scoped pending-answer registry ---

_ask_user_pending: dict[str, dict] = {}
_ask_user_lock = threading.Lock()

# --- Workflow-scoped pending file uploads ---
# Keyed by workflow execution_id. The frontend POSTs the uploaded file path
# (after writing it to a known location) to /v1/workflows/executions/<id>/file
# which calls deliver_workflow_file_answer().
_workflow_file_pending: dict[str, dict] = {}
_workflow_file_lock = threading.Lock()


def _workflow_file_register(execution_id: str) -> threading.Event:
    event = threading.Event()
    with _workflow_file_lock:
        _workflow_file_pending[execution_id] = {"event": event, "result": None}
    return event


def _workflow_file_clear(execution_id: str) -> None:
    with _workflow_file_lock:
        _workflow_file_pending.pop(execution_id, None)


def deliver_workflow_file_answer(execution_id: str, payload: dict | None) -> bool:
    """Called by the upload endpoint. payload = {path, filename, size_bytes} or None to cancel."""
    with _workflow_file_lock:
        slot = _workflow_file_pending.get(execution_id)
        if not slot:
            return False
        slot["result"] = payload
        slot["event"].set()
    return True


def tool_ask_user_for_file(args: dict) -> str:
    """Pause and request a file upload from the user.

    Routes the request via the active event_callback as a 'file_upload_needed' SSE event,
    then blocks on a pending-file slot keyed by execution_id (workflow) or session_id (chat).
    Frontend uploads the file to /v1/workflows/upload-pending which delivers the answer.
    """
    prompt = args.get("prompt") or "Please upload a file"
    accept = args.get("accept") or ""
    timeout = int(args.get("timeout_seconds", 600))

    # Prefer workflow execution_id; fall back to session_id for chat use.
    execution_id = getattr(_thread_local, "workflow_execution_id", None)
    session_id = getattr(_thread_local, "current_session_id", None)
    key = execution_id or session_id
    if not key:
        return _err("ask_user_for_file requires an active workflow execution or chat session")

    cb = getattr(_thread_local, "event_callback", None)
    if cb:
        try:
            cb("file_upload_needed", {
                "execution_id": execution_id or "",
                "session_id": session_id or "",
                "prompt": prompt,
                "accept": accept,
                "timeout_seconds": timeout,
            })
        except Exception:
            pass

    event = _workflow_file_register(key)
    try:
        got = event.wait(timeout=timeout)
        if not got:
            return _err("ask_user_for_file: timed out waiting for upload")
        with _workflow_file_lock:
            slot = _workflow_file_pending.get(key) or {}
            payload = slot.get("result")
        if not payload:
            return _err("ask_user_for_file: cancelled by user")
        return _ok({
            "path": payload.get("path", ""),
            "filename": payload.get("filename", ""),
            "size_bytes": int(payload.get("size_bytes") or 0),
        })
    finally:
        _workflow_file_clear(key)



def _ask_user_register(session_id: str) -> threading.Event:
    """Create a pending-answer slot for a session. Returns the Event to wait on."""
    event = threading.Event()
    with _ask_user_lock:
        _ask_user_pending[session_id] = {"event": event, "answer": None}
    return event


def _ask_user_clear(session_id: str) -> None:
    with _ask_user_lock:
        _ask_user_pending.pop(session_id, None)


def deliver_ask_user_answer(session_id: str, answer=None, answers=None) -> bool:
    """Called by POST /v1/chat/answer. Returns True if a pending question was matched.

    Accepts either `answer` (string, single-question) or `answers` (dict keyed by question, batch).
    """
    with _ask_user_lock:
        slot = _ask_user_pending.get(session_id)
        if not slot:
            return False
        if answers is not None:
            slot["answers"] = answers
        if answer is not None:
            slot["answer"] = answer
        slot["event"].set()
    return True


def _normalize_ask_questions(args: dict):
    """Return (questions_list, is_batch) from args.

    - `questions: [{question, options?}, ...]` → batch
    - `question: "..."` (+ optional `options`) → single, wrapped
    Returns ([], False) on invalid input.
    """
    qs = args.get("questions")
    if isinstance(qs, list) and qs:
        out = []
        for q in qs:
            if isinstance(q, dict) and q.get("question"):
                out.append({
                    "question": str(q["question"]),
                    "options": q.get("options") if isinstance(q.get("options"), list) else None,
                })
        return out, True
    q = args.get("question")
    if isinstance(q, str) and q:
        return [{"question": q, "options": args.get("options") if isinstance(args.get("options"), list) else None}], False
    return [], False


def tool_ask_user(args: dict) -> str:
    """Ask the user one or more questions from the main chat loop (not inside a worker)."""
    session_id = getattr(_thread_local, 'current_session_id', None)
    if not session_id:
        return _err("ask_user requires an active session")
    questions, is_batch = _normalize_ask_questions(args)
    if not questions:
        return _err("question or questions is required")
    context_summary = args.get("context_summary", "")
    timeout = int(args.get("timeout_seconds", 300))

    cb = getattr(_thread_local, 'event_callback', None)
    if cb:
        try:
            payload = {
                "session_id": session_id,
                "questions": questions,
                "context_summary": context_summary,
                "timeout_seconds": timeout,
            }
            if not is_batch:
                # Keep legacy fields for single-question consumers
                payload["question"] = questions[0]["question"]
                payload["options"] = questions[0]["options"]
            cb("user_input_needed", payload)
        except Exception:
            pass

    event = _ask_user_register(session_id)
    try:
        got = event.wait(timeout=timeout)
        if not got:
            return _err("No answer received (timed out)")
        with _ask_user_lock:
            slot = _ask_user_pending.get(session_id) or {}
            answers_map = slot.get("answers")
            answer_str = slot.get("answer")
        if is_batch:
            if not isinstance(answers_map, dict) or not answers_map:
                return _err("No answers received")
            if cb:
                try:
                    cb("user_input_received", {"session_id": session_id, "answers": answers_map})
                except Exception:
                    pass
            return _ok({"answers": answers_map})
        # Single-question path. Prefer explicit answer, fall back to first value in answers map.
        if answer_str is None and isinstance(answers_map, dict) and answers_map:
            answer_str = next(iter(answers_map.values()))
        if answer_str is None:
            return _err("No answer received")
        if cb:
            try:
                cb("user_input_received", {"session_id": session_id, "answer": answer_str})
            except Exception:
                pass
        return _ok({"answer": answer_str})
    finally:
        _ask_user_clear(session_id)


